db.books.aggregate([
  // Viết stage $lookup của bạn ở đây
]);

db.books.aggregate([
  {
    $lookup: {
      from: "authors",
      localField: "author_id",
      foreignField: "_id",
      as: "authorDetails"
    }
  },
  // Viết stage $unwind của bạn ở đây
]);

db.books.aggregate([
  {
    $lookup: {
      from: "authors",
      localField: "author_id",
      foreignField: "_id",
      as: "authorDetails"
    }
  },
  {
    $unwind: "$authorDetails"
  },
  // Viết stage $match của bạn ở đây
]);

