db.books.aggregate([
  // ... các stage trước đó ...
  {
    $match: { "authorDetails.name": "George Orwell" }
  },
  // Viết stage $project của bạn ở đây
]);

codeExercises.solution:
db.books.aggregate([
  {
    $lookup: { from: "authors", localField: "author_id", foreignField: "_id", as: "authorDetails" }
  },
  {
    $unwind: "$authorDetails"
  },
  {
    $match: { "authorDetails.name": "George Orwell" }
  },
  {
    $project: {
      _id: 0,
      title: "$title",
      authorName: "$authorDetails.name",
      birthYear: "$authorDetails.birth_year"
    }
  }
]);

codeExercises.starterCode:
db.books.aggregate([
  // Viết các stage cần thiết ở đây
]);

codeExercises.solution:
db.books.aggregate([
  {
    $lookup: {
      from: "authors",
      localField: "author_id",
      foreignField: "_id",
      as: "authorDetails"
    }
  },
  {
    $unwind: "$authorDetails"
  },
  {
    $group: {
      _id: "$authorDetails.name",
      bookCount: { $sum: 1 }
    }
  },
  {
    $project: {
      _id: 0,
      authorName: "$_id",
      bookCount: 1
    }
  }
]);
